<template><div class="page-container"><PageHeader eyebrow="PEOPLE" title="人物中心" description="声优、演员、导演和其他创作者档案"/><div class="filter-panel"><el-input v-model="keyword" placeholder="搜索人物姓名" @keyup.enter="load"/><el-input v-model="country" placeholder="国家或地区"/><el-button type="primary" @click="load">搜索</el-button></div><div v-loading="loading" class="profile-grid"><router-link v-for="item in page.list" :key="item.id" :to="`/persons/${item.id}`" class="profile-card"><div class="profile-image"><img v-if="item.avatarUrl" :src="item.avatarUrl"><div v-else class="avatar-placeholder">{{ item.name?.[0] }}</div></div><div><h3>{{ item.name }}</h3><el-tag size="small" type="success">{{ item.country||'地区未知' }}</el-tag><p>{{ truncate(item.introduction,85) }}</p></div></router-link></div><EmptyState v-if="!loading&&!page.list.length"/><div class="pagination-wrap"><el-pagination background :total="page.total" :page-size="size" v-model:current-page="current" @current-change="load"/></div></div></template>
<script setup>import { onMounted,reactive,ref } from 'vue';import PageHeader from '../../components/PageHeader.vue';import EmptyState from '../../components/EmptyState.vue';import { personApi } from '../../api/person';import { normalizePage } from '../../utils/page';import { truncate } from '../../utils/format';const keyword=ref(''),country=ref(''),current=ref(1),size=12,loading=ref(false),page=reactive({list:[],total:0});async function load(){loading.value=true;try{const data=keyword.value?await personApi.search({keyword:keyword.value,current:current.value,size}):await personApi.page({current:current.value,size,country:country.value||undefined});Object.assign(page,normalizePage(data))}finally{loading.value=false}}onMounted(load)</script>
